import test from "node:test";
import assert from "node:assert/strict";
import { formatPost } from "../src/posts.js";
import { formatUser } from "../src/users.js";
import { slugify } from "../src/slugify.js";

test("shared slugify exists", () => {
  assert.equal(slugify("Hello World!"), "hello-world");
});

test("posts use shared behavior", () => {
  assert.equal(formatPost("Hello World!").slug, "hello-world");
});

test("users use shared behavior", () => {
  assert.equal(formatUser("Ada Lovelace").slug, "ada-lovelace");
});
